<?php $d=__DIR__.'/../stats/';if(!is_dir($d))@mkdir($d,0775,true);$ip=@$_SERVER['REMOTE_ADDR'];$day=@date('d');$secret='ChangeMoiParUnSecretSimple';$raw=hash_hmac('sha256',$ip.$day,$secret,true);$id=rtrim(strtr(base64_encode($raw),'+/','-_'),'=');$f1=$d."id_jour_$day.txt";$f2=$d."visiteurs_jour_$day.txt";$f3=$d."visites_jour_$day.txt";if(!@file_exists($f1)){@file_put_contents($f1,'');@chmod($f1,0775);}if(!@file_exists($f2)){@file_put_contents($f2,'0');@chmod($f2,0775);}if(!@file_exists($f3)){@file_put_contents($f3,'0');@chmod($f3,0775);} $ids=@file_get_contents($f1);if(@strpos($ids,$id."\n")===false){@file_put_contents($f1,$id."\n",FILE_APPEND);$v=(int)@file_get_contents($f2);@file_put_contents($f2,$v+1);} $vt=(int)@file_get_contents($f3);@file_put_contents($f3,$vt+1);if(@filesize($f1)>262144){$t=@date('Hi');$gz=$d."id_jour_{$day}_{$t}.txt.gz";$data=@file_get_contents($f1);$gzdata=@gzencode($data,1);@file_put_contents($gz,$gzdata);} $fs=@glob($d."id_jour_*.txt.gz");if(@count($fs)>320){@array_multisort(@array_map('filemtime',$fs),SORT_NUMERIC,SORT_ASC,$fs);while(@count($fs)>320){@unlink(array_shift($fs));}} foreach(@glob($d."*")as$f){if(@filemtime($f)<@time()-2682000)@unlink($f);}?>
